import { describe, expect, it } from 'vitest';
import {
  createGraphViewAnalysisProgressForwarder,
  sendInitialGraphViewAnalysisProgress,
} from '../../../../../src/extension/graphView/analysis/execution/progress';
import { createExecutionHandlers } from './fixtures';

describe('graph view analysis execution progress', () => {
  it('forwards progress updates with the phase label for the current mode', () => {
    const { handlers } = createExecutionHandlers();

    createGraphViewAnalysisProgressForwarder('refresh', handlers)({
      phase: 'ignored',
      current: 2,
      total: 5,
    });

    expect(handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Refreshing Index',
      current: 2,
      total: 5,
    });
  });

  it('publishes the initial progress state for indexed modes only', () => {
    const indexed = createExecutionHandlers();
    const loaded = createExecutionHandlers();
    const refreshed = createExecutionHandlers();
    const incremental = createExecutionHandlers();
    const analyzed = createExecutionHandlers();

    sendInitialGraphViewAnalysisProgress('index', indexed.handlers);
    sendInitialGraphViewAnalysisProgress('load', loaded.handlers);
    sendInitialGraphViewAnalysisProgress('refresh', refreshed.handlers);
    sendInitialGraphViewAnalysisProgress('incremental', incremental.handlers);
    sendInitialGraphViewAnalysisProgress('analyze', analyzed.handlers);

    expect(indexed.handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Indexing Repo',
      current: 0,
      total: 1,
    });
    expect(refreshed.handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Refreshing Index',
      current: 0,
      total: 1,
    });
    expect(incremental.handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Applying Changes',
      current: 0,
      total: 1,
    });
    expect(loaded.handlers.sendIndexProgress).not.toHaveBeenCalled();
    expect(analyzed.handlers.sendIndexProgress).not.toHaveBeenCalled();
  });

  it('does not throw when progress handlers omit sendIndexProgress', () => {
    expect(() =>
      createGraphViewAnalysisProgressForwarder('analyze', {} as never)({
        phase: 'ignored',
        current: 1,
        total: 2,
      }),
    ).not.toThrow();
  });
});

import { describe, expect, it, vi } from 'vitest';
import { prepareGraphViewAnalysis } from '../../../../../src/extension/graphView/analysis/execution/prepare';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution prepare', () => {
  it('returns before doing any work when the request is already stale', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn(() => true),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.computeMergedGroups).not.toHaveBeenCalled();
    expect(handlers.setRawGraphData).not.toHaveBeenCalled();
  });

  it('publishes an empty graph when no analyzer exists', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers();

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.setGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('stops when the request turns stale after initialization', async () => {
    const initialize = vi.fn(async () => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
    });
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn()
        .mockReturnValueOnce(false)
        .mockReturnValueOnce(false)
        .mockReturnValueOnce(true),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(initialize).toHaveBeenCalledOnce();
    expect(handlers.computeMergedGroups).not.toHaveBeenCalled();
  });

  it('publishes an empty graph after group recompute when no workspace is available', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers({
      hasWorkspace: vi.fn(() => false),
    });

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);

    expect(handlers.computeMergedGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('returns true after plugin activation, initialization, and group preparation succeed', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
      installedPluginActivationPromise: Promise.resolve(),
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      prepareGraphViewAnalysis(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(handlers.computeMergedGroups).toHaveBeenCalledOnce();
    expect(handlers.sendGroupsUpdated).toHaveBeenCalledOnce();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IGraphData } from '../../../../../src/shared/graph/types';
import {
  publishAnalyzedGraph,
  publishAnalysisFailure,
  publishEmptyGraph,
} from '../../../../../src/extension/graphView/analysis/execution/publish';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution publish', () => {
  it('publishes an empty graph and index state', () => {
    const { handlers } = createExecutionHandlers();

    const graphData = publishEmptyGraph(handlers, true);

    expect(graphData).toEqual({ nodes: [], edges: [] });
    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.setGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(true);
    expect(handlers.sendDepthState).toHaveBeenCalledOnce();
  });

  it('defaults empty graph publication to a missing index', () => {
    const { handlers } = createExecutionHandlers();

    publishEmptyGraph(handlers);

    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(false);
  });

  it('publishes the transformed graph and notifies post-analyze hooks', () => {
    const rawGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const transformedGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        analyze: vi.fn(() => Promise.resolve(rawGraphData)),
      }),
    });
    const { handlers, getGraphData } = createExecutionHandlers({
      applyViewTransform: vi.fn(() => {
        handlers.setGraphData(transformedGraphData);
      }),
    });

    publishAnalyzedGraph(state, handlers, rawGraphData, true);

    expect(handlers.updateViewContext).toHaveBeenCalledOnce();
    expect(handlers.applyViewTransform).toHaveBeenCalledOnce();
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith(transformedGraphData);
    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.sendDecorations).toHaveBeenCalledOnce();
    expect(handlers.sendContextMenuItems).toHaveBeenCalledOnce();
    expect(state.analyzer?.registry.notifyPostAnalyze).toHaveBeenCalledWith(getGraphData());
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith(getGraphData());
  });

  it('publishes the transformed graph without post-analyze hooks when no analyzer is available', () => {
    const rawGraphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    };
    const state = createExecutionState();
    const { handlers, getGraphData } = createExecutionHandlers();

    expect(() => publishAnalyzedGraph(state, handlers, rawGraphData, false)).not.toThrow();

    expect(handlers.sendGraphIndexStatusUpdated).toHaveBeenCalledWith(false);
    expect(handlers.sendGraphDataUpdated).toHaveBeenCalledWith(getGraphData());
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith(getGraphData());
  });

  it('publishes an empty graph fallback with plugin state updates after failures', () => {
    const { handlers } = createExecutionHandlers({
      sendPluginExporters: vi.fn(),
      sendPluginToolbarActions: vi.fn(),
    });

    publishAnalysisFailure(handlers);

    expect(handlers.setRawGraphData).toHaveBeenCalledWith({ nodes: [], edges: [] });
    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.sendPluginExporters).toHaveBeenCalledOnce();
    expect(handlers.sendPluginToolbarActions).toHaveBeenCalledOnce();
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });

  it('publishes an empty graph fallback when optional plugin broadcasts are absent', () => {
    const { handlers } = createExecutionHandlers();

    expect(() => publishAnalysisFailure(handlers)).not.toThrow();

    expect(handlers.sendPluginStatuses).toHaveBeenCalledOnce();
    expect(handlers.markWorkspaceReady).toHaveBeenCalledWith({ nodes: [], edges: [] });
  });
});

import { describe, expect, it, vi } from 'vitest';
import { loadGraphViewRawData } from '../../../../../src/extension/graphView/analysis/execution/load';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution load', () => {
  it('discovers a disconnected graph when loading without an existing index', async () => {
    const discoverGraph = vi.fn(async () => ({
      nodes: [{ id: 'src/index.ts', label: 'src/index.ts', color: '#ffffff' }],
      edges: [],
    }));
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'load',
      analyzer: createExecutionAnalyzer({
        hasIndex: vi.fn(() => false),
        discoverGraph,
        analyze,
      }),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    const result = await loadGraphViewRawData(new AbortController().signal, state, handlers);

    expect(result.shouldDiscover).toBe(true);
    expect(discoverGraph).toHaveBeenCalledOnce();
    expect(analyze).not.toHaveBeenCalled();
    expect(handlers.sendIndexProgress).not.toHaveBeenCalled();
  });

  it('analyzes the workspace when loading from an existing index', async () => {
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'load',
      analyzer: createExecutionAnalyzer({
        hasIndex: vi.fn(() => true),
        analyze,
      }),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    const result = await loadGraphViewRawData(new AbortController().signal, state, handlers);

    expect(result.shouldDiscover).toBe(false);
    expect(analyze).toHaveBeenCalledOnce();
  });

  it('runs explicit full refresh through the analyzer refresh path', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        refreshIndex: vi.fn(async (_patterns, _disabledPlugins, _signal, onProgress) => {
          onProgress?.({ phase: 'Refreshing Index', current: 1, total: 3 });
          return { nodes: [], edges: [] };
        }),
      }),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    await loadGraphViewRawData(new AbortController().signal, state, handlers);

    expect(handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Refreshing Index',
      current: 0,
      total: 1,
    });
    expect(handlers.sendIndexProgress).toHaveBeenCalledWith({
      phase: 'Refreshing Index',
      current: 1,
      total: 3,
    });
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  refreshGraphViewRawData,
  refreshIncrementalGraphViewRawData,
} from '../../../../../src/extension/graphView/analysis/execution/refresh';
import {
  createExecutionAnalyzer,
  createExecutionState,
} from './fixtures';
import { EMPTY_GRAPH_DATA } from '../../../../../src/extension/graphView/analysis/execution/publish';

describe('graph view analysis execution refresh', () => {
  it('runs explicit full refresh through the analyzer refresh path', async () => {
    const refreshIndex = vi.fn(async () => ({ nodes: [], edges: [] }));
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex,
      }),
      analyzerInitialized: true,
    });

    await refreshGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshIndex).toHaveBeenCalledOnce();
    expect(analyze).not.toHaveBeenCalled();
  });

  it('falls back to analyzer analyze for full refreshes when refreshIndex is unavailable', async () => {
    const analyze = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual({ nodes: [], edges: [] });
    expect(analyze).toHaveBeenCalledOnce();
  });

  it('runs scoped incremental refresh through the changed-file analyzer path', async () => {
    const refreshChangedFiles = vi.fn(async () => ({ nodes: [], edges: [] }));
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: ['src/index.ts'],
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn());

    expect(refreshChangedFiles).toHaveBeenCalledWith(
      ['src/index.ts'],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to analyzer analyze when incremental refresh support is unavailable', async () => {
    const analyzeResult = { nodes: [], edges: [] };
    const analyze = vi.fn(async () => analyzeResult);
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: createExecutionAnalyzer({
        analyze,
        refreshChangedFiles: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(analyzeResult);

    expect(analyze).toHaveBeenCalledOnce();
  });

  it('uses empty changed-file paths for incremental refreshes and falls back to the empty graph', async () => {
    const refreshChangedFiles = vi.fn(async () => undefined as never);
    const state = createExecutionState({
      mode: 'incremental',
      changedFilePaths: undefined,
      analyzer: createExecutionAnalyzer({
        refreshChangedFiles,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toEqual(EMPTY_GRAPH_DATA);
    expect(refreshChangedFiles).toHaveBeenCalledWith(
      [],
      [],
      new Set<string>(),
      expect.any(AbortSignal),
      expect.any(Function),
    );
  });

  it('falls back to the empty graph when no refresh or analyze path is available', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: createExecutionAnalyzer({
        analyze: undefined,
        refreshIndex: undefined,
      }),
      analyzerInitialized: true,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for a full refresh', async () => {
    const state = createExecutionState({
      mode: 'refresh',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });

  it('falls back to the empty graph when no analyzer exists for an incremental refresh', async () => {
    const state = createExecutionState({
      mode: 'incremental',
      analyzer: undefined,
      analyzerInitialized: false,
    });

    await expect(
      refreshIncrementalGraphViewRawData(new AbortController().signal, state, vi.fn()),
    ).resolves.toBe(EMPTY_GRAPH_DATA);
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  awaitGraphViewPluginActivation,
  ensureGraphViewAnalyzerInitialized,
} from '../../../../../src/extension/graphView/analysis/execution/initialize';
import {
  createExecutionAnalyzer,
  createExecutionHandlers,
  createExecutionState,
} from './fixtures';

describe('graph view analysis execution initialize', () => {
  it('returns true immediately when the analyzer is already initialized', async () => {
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer(),
      analyzerInitialized: true,
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(state.analyzer?.initialize).not.toHaveBeenCalled();
  });

  it('returns false when no analyzer exists', async () => {
    const state = createExecutionState();
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);
  });

  it('initializes the analyzer once and clears the cached promise', async () => {
    const initialize = vi.fn(async () => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(initialize).toHaveBeenCalledOnce();
    expect(state.analyzerInitialized).toBe(true);
    expect(state.analyzerInitPromise).toBeUndefined();
  });

  it('reuses an in-flight analyzer initialization promise', async () => {
    const initialize = vi.fn(async () => undefined);
    const analyzerInitPromise = Promise.resolve().then(() => undefined);
    const state = createExecutionState({
      analyzer: createExecutionAnalyzer({
        initialize,
      }),
      analyzerInitPromise,
    });
    const { handlers } = createExecutionHandlers();

    await expect(
      ensureGraphViewAnalyzerInitialized(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(true);

    expect(initialize).not.toHaveBeenCalled();
    expect(state.analyzerInitialized).toBe(false);
    expect(state.analyzerInitPromise).toBe(analyzerInitPromise);
  });

  it('returns false when the request turns stale after plugin activation', async () => {
    const state = createExecutionState({
      installedPluginActivationPromise: Promise.resolve(),
    });
    const { handlers } = createExecutionHandlers({
      isAnalysisStale: vi.fn(() => true),
    });

    await expect(
      awaitGraphViewPluginActivation(new AbortController().signal, 1, state, handlers),
    ).resolves.toBe(false);
  });
});

import { describe, expect, it, vi } from 'vitest';
